#include <stdio.h>
#include <stdlib.h>
#include <time.h>

// Function to write error messages to log file
void writeErrorToLogFile(const char* errmsg)
{
    time_t t = time(NULL);
    struct tm* tm_info = localtime(&t);
    char time_str[26];

    strftime(time_str, sizeof(time_str), "%Y-%m-%d %H:%M:%S", tm_info);

    FILE* logfile = fopen("error_log.txt", "a");

    if(logfile == NULL)
    {
        fprintf(stderr, "Unable to open log file.\n");
        exit(1);
    }

    fprintf(logfile, "[%s]: %s\n", time_str, errmsg);

    fclose(logfile);
}